// Note is the resolver for the note field.
func (r *queryResolver) Note(ctx context.Context, input model.NoteInput) (*model.PublicNote, error) {
	req, err := appreq.FromCtx(ctx)
	if err != nil {
		return nil, err
	}

	userToken, err := req.UserToken()
	if err != nil {
		return nil, err
	}

	var path string

	if input.Path != nil {
		path = *input.Path
	}

	if input.PathID != nil {
		latestViews := r.env(ctx).LatestNoteViews()

		for _, view := range latestViews.List {
			if view.PathID == *input.PathID {
				path = view.Permalink
				break
			}
		}
	}

	request := rendernotepage.Request{
		Path:      path,
		Referrer:  input.Referer,
		UserToken: userToken,
	}

	response, err := rendernotepage.Resolve(ctx, r.env(ctx), request)
	if err != nil {
		return nil, err
	}

	if response.Note == nil {
		return nil, nil
	}

	return model.ConvertNoteToPublic(response.Note), nil
}

